const fs = require('fs');
const path = require('path');
const contacts = JSON.parse(fs.readFileSync(path.join('Working', $json.project_prefix, 'contacts.json'), 'utf8'));
return contacts.filter(c => c.valid_format).map(c => ({ json: { project_prefix: $json.project_prefix, ...c } }));

// SearXNG on-demand (B2): started here, stopped after. Idempotent
// named-container cleanup first so an orphaned prior instance never
// causes a port-bind collision, regardless of host OS.
const { execSync } = require('child_process');
try { execSync('docker stop circleofcare-searxng', { stdio: 'ignore' }); } catch (e) {}
try { execSync('docker rm circleofcare-searxng', { stdio: 'ignore' }); } catch (e) {}
execSync('docker run -d --name circleofcare-searxng -p 127.0.0.1:8888:8080 searxng/searxng', { stdio: 'ignore' });
return $input.all();

// Deterministic pre-filter: top 3 snippets, URLs/metadata stripped,
// compressed under 1,000 tokens BEFORE it ever reaches the model.
const results = ($json.results || []).slice(0, 3);
const compact = results.map(r => r.content || r.title || '').join(' ').slice(0, 4000);
return [{ json: { ...($json), compact_snippet: compact } }];

